previewCss:
.darma-loader-darma-custom-334 {color: var(--loader-color, #16a34a);
  --loader-secondary-color: var(--loader-secondary-color, #86efac);
  --loader-bg: var(--loader-bg, #ffffff);
  height: 70px;
  aspect-ratio: 1;
  padding: 10px;
  border-radius: 20px;
  box-sizing: border-box;
  position: relative;
  mask: conic-gradient(currentColor 0 0) content-box exclude,conic-gradient(currentColor 0 0);
  filter: blur(12px);
}.darma-loader-darma-custom-334:before {content: "";
  position: absolute;
  inset: 0;
  background: repeating-conic-gradient(#0000 0 5%,var(--loader-color, #16a34a),#0000 20% 50%);
  animation: darma-loader-darma-custom-334-l3 1.5s linear infinite;
}@keyframes darma-loader-darma-custom-334-l3 {to {rotate: 1turn}}

